VALUES
  ('social-worker-moex-02036', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於自助或互助團體的討論，下列敘述何者錯誤？', '["在失智症患者之照顧者團體中，照顧者能從中得到關心和支持", "在特殊需求兒童之家長團體中，家長能從中得到有關因應孩子問題的資訊", "在身心障礙者之照顧者團體中，家庭有需要時，能夠取得物質的協助", "專業人員積極介入團體是有其必要性，必須強化團體成員的專業知能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02037', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '自我效能（self-efficacy）是那一種理論的重要觀點？', '["Freud心理動力理論", "Piaget的認知理論", "Bandura的社會學習理論", "Erikson的社會心理理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02038', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '羅伯恩萊特（Robert Enright）提出寬恕的四個階段，原則上是以下列那一種順序發展？', '["找出憤怒－決定寬恕－努力寬恕－發現與解放", "找出憤怒－努力寬恕－決定寬恕－發現與解放", "發現與解放－找出憤怒－決定寬恕－努力寬恕", "決定寬恕－找出憤怒－努力寬恕－發現與解放"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02039', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '多數父母對孩子是以權威的方式，強迫青少年子女有所承諾，例如學業成就的追求；此一事態使得青少 年未必有機會深思自己的看法或觀點。請問，上述現象符合James Marcia提及之何項青少年自我認同的 分類？', '["認定擴散（identity diffusion）", "認定喪失主動權（identity foreclosure）", "認定延期償付（identity moratorium）", "認定達成（identity achievement）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02040', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關兒童早期的溝通違常，下列敘述何者錯誤？', '["發展性的表達違常，通常是在三歲的時候會出現", "有關發展性的表達違常，有少數兒童在理解方面是有困難的", "口吃僅是急於表達所致，不是溝通違常的類型", "就性別比例而論，男童出現溝通違常的比例較女童高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02041', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '以下對於成年中期（中年階段）的敘述，何者有誤？', '["Erikson認為成年中期的發展主題是生產與停滯", "「差異」可被視為成年中期的最佳寫照", "成年中期與其他階段不同的是，比較少受到生理變化的影響，但很受個人經驗的影響", "「中年危機」讓人處於成年中期時，都會充滿對於工作生活的不確定感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02042', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關憤怒、罪惡感與羞愧三種情緒的敘述，何者有誤？', '["此三種情緒都具有正向功能", "感到罪惡感是因為自我不好，感到羞愧是因為行為本身不好", "憤怒能讓個人在面對人際關係受到威脅時，取得自我控制感", "和有罪惡感傾向的人相較之下，容易羞愧的人比較沒有同理心，比較容易生氣與憤怒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02043', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關成年晚期（老年期）的敘述，何者有誤？', '["為考量服務使用的公平性，協助失能、認知有缺陷或虛弱老人，成功老化的策略，應和協助一般老人 是一致的", "成功老化模式忽略了社會不公平的狀態，讓許多人無法達到成功老化的目標", "活動理論（activity theory）認為，成功老化的關鍵在於能夠適應角色的失落，以新的角色替代舊的角色", "老年超越理論（gerotranscendence）認為最佳的老化是由靈性的成分所組成，這些成分可讓老年人超越 自己對老化的關注"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02044', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「兒童中期」（介於6歲到12歲）的敘述，何者有誤？', '["若以兒童中期認知發展的里程來看，這個階段的兒童若目擊犯罪或是虐待、犯罪的受害者，他們為這 些事情出庭作證的條件，是必須具備將經驗正確地表達出來的能力", "這個階段的兒童，開始有「物體質量恆存（conservation）」的概念，但仍會以自我為中心，在思考運 作上還沒有具備「倒轉（reversibility）」的能力", "12歲的兒童，「角色採取（role-taking）」的能力開始轉變，除了思考自己也會思考社會關係", "在這個階段，兒童會開始增加與同儕相處的時間，他們會開始形成所謂的同儕團體，就是我們常提到 的「小圈圈（cliques）」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02045', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關佛洛依德（Sigmund Freud）「人格結構」的敘述，何者有誤？', '["人格結構分為本我（id）、自我（ego）與超我（superego）三個成分", "自我負責協調本我與超我之間的衝突，自我對來自環境的要求做出反應，並幫助個人在環境中有效地 發揮作用", "超我包括個人心中的道德格言：良心（conscience）以及個人成為道德高尚者的潛在自我理想（ego ideal）", "本我（id）依據現實原則（reality principle）來表現其生物的基本需要，此種思維稱為「原始過程思維 （primary process thought）」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02046', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '若孕婦在懷孕期間過量地飲酒，那麼產下的嬰兒極有可能會出現胎兒酒精症候群。下列何者不是此先天 性缺陷造成的長期影響？', '["注意力不佳", "肌肉協調不良", "過動行為問題", "戒毒症狀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02047', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關影響孕期發展因子的敘述，何者有誤？', '["新生兒發展上的缺陷，可能來自於先天遺傳的限制，也可能受到後天環境因素的影響", "文化對於懷孕過程中孕婦的行為要求、孕婦對生育的態度等影響孕期發展的因素，會同時影響孕婦幸 福感及胎兒健康與成長", "母親年齡會影響生育的品質，愈年輕的母親，身體機能愈好，較易生出健康的胎兒", "婦女於妊娠期間獲取適當的營養，將有助於胎兒的健康"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02048', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「一個人能從他人的立場來看待一種情境的能力。」以上敘述屬於那個概念？', '["人際覺察", "觀點取替", "角色取替", "角色模仿"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02049', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「性別角色社會化（sex-role socialization）」的敘述，何者有誤？', '["女性投入工作市場，造成社會經濟力的提升，而女性在家庭中的角色與期望，因為家庭經濟力提升而 減少", "性別角色社會化受到「男女兩性對職業成功的有關技能有不同期望」的影響", "性別角色社會化受到「男女兩性有不同的價值觀」的影響", "性別角色認同影響人的生涯目標和相應選擇的態度及價值觀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02050', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「生命歷程觀點（life course perspective）」的敘述，何者有誤？', '["生命歷程觀點強調人類的相互依賴生活模式，以及家庭是經歷世事、生命故事的主要舞台", "生命歷程觀點認定，歷史社會變遷的脈絡會影響人類的行為", "生命歷程觀點明辨認定人類生命的時間規劃點，尤其重視心理年齡的重要性", "生命歷程觀點強調人類生命旅程的多元樣貌，以及其相連結的社會資源脈絡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02051', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青春期最重要的任務就是認同形成，下列有關Rosenberg（1986）所提出的認同模型概念中，何者正確？', '["認同包括社會認同（social identity）、特質（dispositions）及生理特徵（physical characteristics）三個部分", "青少年認同分為認定擴散（identity diffusion）、認定喪失主動權（identity foreclosure）、認定延期償付 （identity moratorium）及認定達成（identity achievement）四個階段", "個人特質是認同的元素之一，以他人定義為依據；標籤則是由自我定義為依據，而基因左右生理的特徵", "認同迷失階段係指青少年未曾就角色和價值觀進行探索，也不曾身體力行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02052', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「配偶彼此之間並沒有強烈的情感，因為工作上、投資上、外人的觀感、自身對離婚的態度等因素，使 雙方繼續維持婚姻」，此指？', '["空殼婚姻", "虛幻婚姻", "假面婚姻", "曖昧婚姻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02053', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「是一種溫馨或親暱的感覺，包含和另一個人相依存、自我表露以及濃情蜜意等三種元素」，此屬於下 列何者的概念？', '["浪漫依附（romantic attachment）", "靈性（spirituality）", "浪漫的愛情（romantic love）", "親密感（intimacy）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02054', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「強調『性別』是理解個體老化經驗的關鍵因素，伴隨性別而來的權力、特權與地位，都會在生命歷程 中造成不平等和差別待遇的現象，唯有將性別議題納入考量，才足以理解老化歷程」，以上是那一種社 會老年學理論的主要概念？', '["社會建構理論", "性別階層化觀點", "女性主義理論", "生命歷程觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02055', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關老化概念文化差異的敘述，何者有誤？', '["在華人社會中，老人受惠於儒家的孝道觀，相較於西方社會，在家中與社會上占有較高的位置", "大部分老年人因為生理機能衰退，相較其他發展階段，較易有憂鬱傾向與不幸福感受", "性別與種族是影響老年人經濟狀況的重要因素", "老人教育程度較高者，出現功能性限制的時機延後，而壓縮了功能受限的年齡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02056', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「正常發展的里程碑」的敘述，何者錯誤？', '["正常發展的里程碑通常包括出現在生命週期中的重大生理、心理、情緒、智力與社會性的發展", "為了區別何者為正常或病態的發展，我們必須清楚地瞭解任何年齡層正常發展的里程碑", "社會工作者面對每個特定年齡層之功能運作時，必須要能分辨那些是需要、那些是不需要接受處遇的情境", "50歲與65歲以上的人若有睡眠狀況的問題，社會工作者應該一視同仁，都提供進一步的探究"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02057', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「傳統性別的分類不再是鐵律，而是可以被改變的認知與期待；性別是動態的，持續演變與發展出極具 彈性的性別角色及行為。」以上敘述，是那個理論的基本概念？', '["性別角色社會化理論", "性別角色的跨文化觀點", "性別文化適應理論", "性別的社會建構理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02058', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「雙性化人格」（androgyny）的敘述，何者有誤？', '["係指同時擁有傳統上女性陰柔的特質與男性陽剛的特質", "係指男人要像女人，或是女人要像男人", "不論性別為何，每個人都應該被允許發展正向人格特質", "男性也可以像女性一樣，自在的表達情緒感受並發展溝通技巧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02059', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列關於生態系統觀點基本概念的敘述，何者錯誤？', '["社會工作實務包含雙重焦點：人與情境和系統與環境之間的互動", "在處遇關係上，個體與系統兩者都會受到改變作用的影響", "社會工作實務除了提升個體的成長與發展之外，同時也強調環境的改善", "在Bronfenbrenner的架構中，外部系統是指微視系統所在的文化環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02060', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關Sternberg的愛情三角理論的敘述，何者錯誤？', '["圓滿的愛包括親密、激情與承諾三要素", "愛情三角理論指的是親情、愛情與友情三要素", "在一段長期的親密關係中，愛的組成可能會有不同，例如激情會降低，親密度會增加", "愛情三種要素的不同組合可歸類成不同的互動關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
